import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';

export default function StudentProfile() {
  const { user } = useAuth();
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState({ type: '', text: '' });
  const [form, setForm] = useState({ phone: '', address: '', boardingPoint: '', parentPhone: '' });
  const [pwForm, setPwForm] = useState({ currentPassword: '', newPassword: '', confirmPassword: '' });
  const [pwSaving, setPwSaving] = useState(false);

  useEffect(() => {
    axios.get('/students/profile')
      .then(r => {
        setProfile(r.data);
        setForm({
          phone: r.data.user?.phone || '',
          address: r.data.address || '',
          boardingPoint: r.data.boardingPoint || '',
          parentPhone: r.data.parentPhone || '',
        });
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const handleSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    setMsg({ type: '', text: '' });
    try {
      const r = await axios.put('/students/profile', form);
      setProfile(r.data.profile);
      setMsg({ type: 'success', text: 'Profile updated successfully' });
    } catch (err) {
      setMsg({ type: 'error', text: err.response?.data?.message || 'Failed to update profile' });
    } finally {
      setSaving(false);
    }
  };

  const handlePassword = async (e) => {
    e.preventDefault();
    if (pwForm.newPassword !== pwForm.confirmPassword) {
      setMsg({ type: 'error', text: 'New passwords do not match' });
      return;
    }
    setPwSaving(true);
    setMsg({ type: '', text: '' });
    try {
      await axios.put('/auth/change-password', {
        currentPassword: pwForm.currentPassword,
        newPassword: pwForm.newPassword,
      });
      setPwForm({ currentPassword: '', newPassword: '', confirmPassword: '' });
      setMsg({ type: 'success', text: 'Password changed successfully' });
    } catch (err) {
      setMsg({ type: 'error', text: err.response?.data?.message || 'Failed to change password' });
    } finally {
      setPwSaving(false);
    }
  };

  if (loading) return <div className="loading-screen" style={{ height: 300 }}><div className="spinner" /></div>;

  return (
    <div>
      <div className="profile-hero">
        <div className="profile-avatar-lg">{user?.name?.charAt(0).toUpperCase()}</div>
        <div>
          <h2>{user?.name}</h2>
          <p>{profile?.studentId} · {profile?.department} · Year {profile?.year}</p>
          <div className="profile-badges">
            <span className="badge badge-student">Student</span>
            {profile?.route && <span className="badge" style={{ background: '#dbeafe', color: '#1d4ed8' }}>🚌 {profile.route.routeNumber}</span>}
          </div>
        </div>
      </div>

      {msg.text && <div className={`alert alert-${msg.type === 'success' ? 'success' : 'error'}`}>{msg.type === 'success' ? '✅' : '⚠️'} {msg.text}</div>}

      <div className="profile-grid">
        <div className="card">
          <div className="card-header"><h3 className="card-title">📋 Academic Details</h3><span className="readonly-tag">Read only</span></div>
          <div className="info-list">
            {[
              ['Student ID', profile?.studentId],
              ['Roll Number', profile?.rollNumber],
              ['Department', profile?.department],
              ['Year / Section', `Year ${profile?.year} · Section ${profile?.section}`],
              ['Email', profile?.user?.email],
              ['Fee Type', profile?.feeType],
              ['Parent Name', profile?.parentName],
              ['Admission Date', profile?.admissionDate],
            ].map(([k, v]) => (
              <div className="info-row" key={k}>
                <span>{k}</span>
                <strong>{v || '—'}</strong>
              </div>
            ))}
          </div>
        </div>

        <div className="card">
          <div className="card-header"><h3 className="card-title">✏️ Update Contact Info</h3></div>
          <form onSubmit={handleSave}>
            <div className="form-group">
              <label>Phone Number</label>
              <input value={form.phone} onChange={e => setForm({ ...form, phone: e.target.value })} placeholder="Your phone number" />
            </div>
            <div className="form-group">
              <label>Address</label>
              <textarea rows={2} value={form.address} onChange={e => setForm({ ...form, address: e.target.value })} placeholder="Your address" />
            </div>
            <div className="form-row">
              <div className="form-group">
                <label>Boarding Point</label>
                <input value={form.boardingPoint} onChange={e => setForm({ ...form, boardingPoint: e.target.value })} placeholder="Bus stop" />
              </div>
              <div className="form-group">
                <label>Parent Phone</label>
                <input value={form.parentPhone} onChange={e => setForm({ ...form, parentPhone: e.target.value })} placeholder="Parent contact" />
              </div>
            </div>
            <button type="submit" className="btn btn-primary" disabled={saving}>
              {saving ? 'Saving...' : '💾 Save Changes'}
            </button>
          </form>
        </div>

        <div className="card">
          <div className="card-header"><h3 className="card-title">🔒 Change Password</h3></div>
          <form onSubmit={handlePassword}>
            <div className="form-group">
              <label>Current Password</label>
              <input type="password" value={pwForm.currentPassword} onChange={e => setPwForm({ ...pwForm, currentPassword: e.target.value })} required />
            </div>
            <div className="form-row">
              <div className="form-group">
                <label>New Password</label>
                <input type="password" value={pwForm.newPassword} onChange={e => setPwForm({ ...pwForm, newPassword: e.target.value })} required minLength={6} />
              </div>
              <div className="form-group">
                <label>Confirm Password</label>
                <input type="password" value={pwForm.confirmPassword} onChange={e => setPwForm({ ...pwForm, confirmPassword: e.target.value })} required />
              </div>
            </div>
            <button type="submit" className="btn btn-outline" disabled={pwSaving}>
              {pwSaving ? 'Updating...' : '🔑 Update Password'}
            </button>
          </form>
        </div>

        {profile?.route && (
          <div className="card route-card-accent">
            <div className="card-header"><h3 className="card-title">🚌 My Bus Route</h3></div>
            <div className="route-visual">
              <div className="route-stop"><span>Start</span><strong>{profile.route.startPoint}</strong></div>
              <div className="route-line" />
              <div className="route-stop route-stop-mid"><span>Your Stop</span><strong>{profile.boardingPoint || '—'}</strong></div>
              <div className="route-line" />
              <div className="route-stop"><span>End</span><strong>{profile.route.endPoint}</strong></div>
            </div>
            <div className="info-list" style={{ marginTop: 16 }}>
              <div className="info-row"><span>Route</span><strong>{profile.route.routeNumber} — {profile.route.routeName}</strong></div>
              <div className="info-row"><span>Monthly Fee</span><strong>₹{Number(profile.route.monthlyFee).toLocaleString('en-IN')}</strong></div>
              <div className="info-row"><span>Distance</span><strong>{profile.route.distanceKm} km</strong></div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
